 */
function uninstallLangPack()
{
    global $sugar_config;

    // remove language from config
    $new_langs = array();
    $old_langs = $sugar_config['languages'];
    foreach ($old_langs as $key => $value) {
        if ($key != $_REQUEST['new_lang_name']) {
            $new_langs += array( $key => $value );
